   764→    for (const panel of this.dashboard.panels) {
   765→      // @ts-expect-error
   766→      if (panel.repeatPanelId || panel.repeatByRow) {
   767→        continue;
   768→      }
   769→
   770→      // Filter out repeats in collapsed rows
   771→      if (panel.type === 'row' && Array.isArray(panel.panels)) {
   772→        panel.panels = panel.panels.filter((x) => !x.repeatPanelId);
   773→      }
   774→
   775→      newPanels.push(panel);
   776→    }
   777→
   778→    this.dashboard.panels = newPanels;
   779→  }
   780→
   781→  // Migrates metric queries and/or annotation queries that use more than one statistic.
   782→  // E.g query.statistics = ['Max', 'Min'] will be migrated to two queries - query1.statistic = 'Max' and query2.statistic = 'Min'
   783→  // New queries, that were created during migration, are put at the end of the array.
   784→  migrateCloudWatchQueries(panel: PanelModel) {
   785→    for (const target of panel.targets || []) {
   786→      if (isCloudWatchQuery(target)) {
   787→        migrateCloudWatchQuery(target);
