  1058→export function migrateDatasourceNameToRef(
  1059→  nameOrRef: string | DataSourceRef | null | undefined,
  1060→  options: MigrateDatasourceNameOptions
  1061→): DataSourceRef | null {
  1062→  if (options.returnDefaultAsNull && (nameOrRef == null || nameOrRef === 'default')) {
  1063→    return null;
  1064→  }
  1065→
  1066→  if (isDataSourceRef(nameOrRef)) {
  1067→    return nameOrRef;
  1068→  }
  1069→
  1070→  const ds = getDataSourceSrv().getInstanceSettings(nameOrRef);
  1071→  if (!ds) {
  1072→    return { uid: nameOrRef ? nameOrRef : undefined }; // not found
  1073→  }
  1074→
  1075→  return getDataSourceRef(ds);
  1076→}
