  1129→function isLegacyCloudWatchAnnotationQuery(
  1130→  target: AnnotationQuery<DataQuery>
  1131→): target is AnnotationQuery<LegacyAnnotationQuery> {
  1132→  return (
  1133→    target.hasOwnProperty('dimensions') &&
  1134→    target.hasOwnProperty('namespace') &&
  1135→    target.hasOwnProperty('region') &&
  1136→    target.hasOwnProperty('prefixMatching') &&
  1137→    target.hasOwnProperty('statistics')
  1138→  );
  1139→}
  1140→
  1141→function upgradeValueMappings(oldMappings: any, thresholds?: ThresholdsConfig): ValueMapping[] | undefined {
  1142→  if (!oldMappings) {
  1143→    return undefined;
  1144→  }
  1145→
  1146→  const valueMaps: ValueMap = { type: MappingType.ValueToText, options: {} };
  1147→  const newMappings: ValueMapping[] = [];
  1148→
  1149→  for (const old of oldMappings) {
  1150→    // when migrating singlestat to stat/gauge, mappings are handled by panel type change handler used in that migration
  1151→    if (old.type && old.options) {
  1152→      // collect al value->text mappings in a single value map object. These are migrated by panel change handler as a separate value maps
  1153→      if (old.type === MappingType.ValueToText) {
  1154→        valueMaps.options = {
  1155→          ...valueMaps.options,
  1156→          ...old.options,
  1157→        };
  1158→      } else {
  1159→        newMappings.push(old);
  1160→      }
  1161→      continue;
  1162→    }
  1163→
  1164→    // Use the color we would have picked from thesholds
  1165→    let color: string | undefined = undefined;
  1166→    const numeric = parseFloat(old.text);
  1167→    if (thresholds && !isNaN(numeric)) {
  1168→      const level = getActiveThreshold(numeric, thresholds.steps);
  1169→      if (level && level.color) {
  1170→        color = level.color;
  1171→      }
  1172→    }
  1173→
  1174→    switch (old.type) {
  1175→      case 1: // MappingType.ValueToText:
  1176→        if (old.value != null) {
  1177→          if (old.value === 'null') {
  1178→            newMappings.push({
  1179→              type: MappingType.SpecialValue,
  1180→              options: {
  1181→                match: SpecialValueMatch.Null,
  1182→                result: { text: old.text, color },
  1183→              },
  1184→            });
  1185→          } else {
  1186→            valueMaps.options[String(old.value)] = {
  1187→              text: old.text,
  1188→              color,
  1189→            };
  1190→          }
  1191→        }
  1192→        break;
  1193→      case 2: // MappingType.RangeToText:
  1194→        newMappings.push({
  1195→          type: MappingType.RangeToText,
  1196→          options: {
  1197→            from: +old.from,
  1198→            to: +old.to,
  1199→            result: { text: old.text, color },
  1200→          },
  1201→        });
  1202→        break;
  1203→    }
  1204→  }
  1205→
  1206→  if (Object.keys(valueMaps.options).length > 0) {
  1207→    newMappings.unshift(valueMaps);
  1208→  }
  1209→
  1210→  return newMappings;
  1211→}
  1212→
  1213→function migrateTooltipOptions(panel: PanelModel) {
  1214→  if (panel.type === 'timeseries' || panel.type === 'xychart' || panel.type === 'xychart2') {
  1215→    if (panel.options.tooltipOptions) {
  1216→      panel.options = {
  1217→        ...panel.options,
  1218→        tooltip: panel.options.tooltipOptions,
  1219→      };
  1220→      delete panel.options.tooltipOptions;
  1221→    }
  1222→  }
  1223→
  1224→  return panel;
  1225→}
  1226→
  1227→// This migration is performed when there is a time series panel with all axes configured to be hidden
  1228→// To avoid breaking dashboards we add override that persists x-axis visibility
  1229→function ensureXAxisVisibility(panel: PanelModel) {
  1230→  if (panel.type === 'timeseries') {
  1231→    if (
  1232→      (panel.fieldConfig as FieldConfigSource<GraphFieldConfig>)?.defaults.custom?.axisPlacement ===
  1233→      AxisPlacement.Hidden
  1234→    ) {
  1235→      panel.fieldConfig = {
  1236→        ...panel.fieldConfig,
  1237→        overrides: [
  1238→          ...panel.fieldConfig.overrides,
  1239→          {
  1240→            matcher: {
  1241→              id: FieldMatcherID.byType,
  1242→              options: FieldType.time,
  1243→            },
  1244→            properties: [
  1245→              {
  1246→                id: 'custom.axisPlacement',
  1247→                value: AxisPlacement.Auto,
  1248→              },
  1249→            ],
  1250→          },
  1251→        ],
  1252→      };
  1253→    }
  1254→  }
  1255→
  1256→  return panel;
  1257→}
  1258→
  1259→function migrateHideFromFunctionality(panel: PanelModel) {
  1260→  // migrate overrides with hideFrom.viz = true to also set tooltip = true
  1261→  // this includes the __systemRef override
  1262→  if (panel.fieldConfig && panel.fieldConfig.overrides) {
  1263→    panel.fieldConfig.overrides = panel.fieldConfig.overrides.map((override) => {
  1264→      if (override.properties) {
  1265→        override.properties = override.properties.map((property) => {
  1266→          if (property.id === 'custom.hideFrom' && property.value?.viz === true) {
  1267→            property.value.tooltip = true;
  1268→          }
  1269→          return property;
  1270→        });
  1271→      }
  1272→      return override;
  1273→    });
  1274→  }
  1275→
  1276→  return panel;
  1277→}
