   757→      this.dashboard.schemaVersion = finalTargetVersion;
   758→    }
   759→  }
   760→
   761→  private removeRepeatedPanels() {
   762→    const newPanels = [];
   763→
   764→    for (const panel of this.dashboard.panels) {
   765→      // @ts-expect-error
   766→      if (panel.repeatPanelId || panel.repeatByRow) {
   767→        continue;
   768→      }
   769→
   770→      // Filter out repeats in collapsed rows
   771→      if (panel.type === 'row' && Array.isArray(panel.panels)) {
   772→        panel.panels = panel.panels.filter((x) => !x.repeatPanelId);
   773→      }
   774→
   775→      newPanels.push(panel);
   776→    }
   777→
   778→    this.dashboard.panels = newPanels;
   779→  }
   780→
   781→  // Migrates metric queries and/or annotation queries that use more than one statistic.
   782→  // E.g query.statistics = ['Max', 'Min'] will be migrated to two queries - query1.statistic = 'Max' and query2.statistic = 'Min'
   783→  // New queries, that were created during migration, are put at the end of the array.
   784→  migrateCloudWatchQueries(panel: PanelModel) {
   785→    for (const target of panel.targets || []) {
   786→      if (isCloudWatchQuery(target)) {
   787→        migrateCloudWatchQuery(target);
   788→        if (target.hasOwnProperty('statistics')) {
   789→          // New queries, that were created during migration, are put at the end of the array.
   790→          const newQueries = migrateMultipleStatsMetricsQuery(target, [...panel.targets]);
   791→          for (const newQuery of newQueries) {
   792→            panel.targets.push(newQuery);
   793→          }
   794→        }
   795→      }
   796→    }
   797→  }
   798→
   799→  // Migrates CloudWatch annotation queries that use multiple statistics into separate queries.
   800→  // For example, if an annotation query uses ['Max', 'Min'] statistics, it will be split into
   801→  // two separate annotation queries - one with 'Max' and another with 'Min'.
   802→  // The new annotation queries are added to the end of the annotations list.
   803→  migrateCloudWatchAnnotationQuery() {
   804→    for (const annotation of this.dashboard.annotations.list) {
   805→      if (isLegacyCloudWatchAnnotationQuery(annotation)) {
   806→        const newAnnotationQueries = migrateMultipleStatsAnnotationQuery(annotation);
   807→        for (const newAnnotationQuery of newAnnotationQueries) {
   808→          this.dashboard.annotations.list.push(newAnnotationQuery);
   809→        }
   810→      }
   811→    }
   812→  }
   813→
   814→  upgradeToGridLayout(old: any) {
   815→    let yPos = 0;
   816→    const widthFactor = GRID_COLUMN_COUNT / 12;
   817→
   818→    const maxPanelId =
   819→      max(
   820→        flattenDeep(
   821→          map(old.rows, (row) => {
   822→            return map(row.panels, 'id');
   823→          })
   824→        ).filter((id) => id != null)
   825→      ) || 0;
   826→    let nextRowId = maxPanelId + 1;
   827→
   828→    if (!old.rows) {
   829→      return;
   830→    }
   831→
   832→    // Add special "row" panels if even one row is collapsed, repeated or has visible title
   833→    const showRows = some(old.rows, (row) => row.collapse || row.showTitle || row.repeat);
   834→
   835→    for (const row of old.rows) {
   836→      if (row.repeatIteration) {
   837→        continue;
   838→      }
   839→
   840→      const height = row.height || DEFAULT_ROW_HEIGHT;
   841→      const rowGridHeight = getGridHeight(height);
   842→
   843→      const rowPanel: any = {};
   844→      let rowPanelModel: PanelModel | undefined;
   845→
   846→      if (showRows) {
   847→        // add special row panel
   848→        rowPanel.id = nextRowId;
   849→        rowPanel.type = 'row';
   850→        rowPanel.title = row.title;
   851→        rowPanel.collapsed = row.collapse;
   852→        rowPanel.repeat = row.repeat;
   853→        rowPanel.panels = [];
   854→        rowPanel.gridPos = {
   855→          x: 0,
   856→          y: yPos,
   857→          w: GRID_COLUMN_COUNT,
   858→          h: rowGridHeight,
   859→        };
   860→        rowPanelModel = new PanelModel(rowPanel);
   861→        nextRowId++;
   862→        yPos++;
   863→      }
   864→
   865→      const rowArea = new RowArea(rowGridHeight, GRID_COLUMN_COUNT, yPos);
   866→
   867→      for (const panel of row.panels) {
   868→        panel.span = panel.span || DEFAULT_PANEL_SPAN;
   869→        if (panel.minSpan) {
   870→          panel.minSpan = Math.min(GRID_COLUMN_COUNT, (GRID_COLUMN_COUNT / 12) * panel.minSpan);
   871→        }
   872→        const panelWidth = Math.floor(panel.span) * widthFactor;
   873→        const panelHeight = panel.height ? getGridHeight(panel.height) : rowGridHeight;
   874→
   875→        const panelPos = rowArea.getPanelPosition(panelHeight, panelWidth);
   876→        yPos = rowArea.yPos;
   877→        panel.gridPos = {
   878→          x: panelPos.x,
   879→          y: yPos + panelPos.y,
   880→          w: panelWidth,
   881→          h: panelHeight,
   882→        };
   883→        rowArea.addPanel(panel.gridPos);
   884→
   885→        delete panel.span;
   886→
   887→        if (rowPanelModel && rowPanel.collapsed) {
   888→          rowPanelModel.panels?.push(panel);
   889→        } else {
   890→          this.dashboard.panels.push(new PanelModel(panel));
   891→        }
   892→      }
   893→
   894→      if (rowPanelModel) {
   895→        this.dashboard.panels.push(rowPanelModel);
   896→      }
   897→
   898→      if (!(rowPanelModel && rowPanel.collapsed)) {
   899→        yPos += rowGridHeight;
   900→      }
   901→    }
   902→  }
   903→}
   904→
   905→function getGridHeight(height: number | string) {
   906→  if (isString(height)) {
   907→    height = parseInt(height.replace('px', ''), 10);
   908→  }
   909→
   910→  if (height < MIN_PANEL_HEIGHT) {
   911→    height = MIN_PANEL_HEIGHT;
   912→  }
   913→
   914→  const gridHeight = Math.ceil(height / (GRID_CELL_HEIGHT + GRID_CELL_VMARGIN));
   915→  return gridHeight;
   916→}
   917→
   918→/**
   919→ * RowArea represents dashboard row filled by panels
   920→ * area is an array of numbers represented filled column's cells like
   921→ *  -----------------------
   922→ * |******** ****
   923→ * |******** ****
   924→ * |********
   925→ *  -----------------------
   926→ *  33333333 2222 00000 ...
   927→ */
   928→class RowArea {
   929→  area: number[];
   930→  yPos: number;
   931→  height: number;
   932→
   933→  constructor(height: number, width = GRID_COLUMN_COUNT, rowYPos = 0) {
   934→    this.area = new Array(width).fill(0);
   935→    this.yPos = rowYPos;
   936→    this.height = height;
   937→  }
   938→
   939→  reset() {
   940→    this.area.fill(0);
   941→  }
   942→
   943→  /**
   944→   * Update area after adding the panel.
   945→   */
   946→  addPanel(gridPos: any) {
   947→    for (let i = gridPos.x; i < gridPos.x + gridPos.w; i++) {
   948→      if (!this.area[i] || gridPos.y + gridPos.h - this.yPos > this.area[i]) {
   949→        this.area[i] = gridPos.y + gridPos.h - this.yPos;
   950→      }
   951→    }
   952→    return this.area;
   953→  }
   954→
   955→  /**
   956→   * Calculate position for the new panel in the row.
   957→   */
   958→  getPanelPosition(panelHeight: number, panelWidth: number, callOnce = false): any {
   959→    let startPlace, endPlace;
   960→    let place;
   961→    for (let i = this.area.length - 1; i >= 0; i--) {
   962→      if (this.height - this.area[i] > 0) {
   963→        if (endPlace === undefined) {
   964→          endPlace = i;
   965→        } else {
   966→          if (i < this.area.length - 1 && this.area[i] <= this.area[i + 1]) {
   967→            startPlace = i;
   968→          } else {
   969→            break;
   970→          }
   971→        }
   972→      } else {
   973→        break;
   974→      }
   975→    }
   976→
   977→    if (startPlace !== undefined && endPlace !== undefined && endPlace - startPlace >= panelWidth - 1) {
   978→      const yPos = max(this.area.slice(startPlace));
   979→      place = {
   980→        x: startPlace,
   981→        y: yPos,
   982→      };
   983→    } else if (!callOnce) {
   984→      // wrap to next row
   985→      this.yPos += this.height;
   986→      this.reset();
   987→      return this.getPanelPosition(panelHeight, panelWidth, true);
   988→    } else {
   989→      return null;
   990→    }
   991→
   992→    return place;
   993→  }
   994→}
   995→
   996→function upgradePanelLink(link: any): DataLink {
   997→  let url = link.url;
   998→
   999→  if (!url && link.dashboard) {
  1000→    url = `dashboard/db/${kbn.slugifyForUrl(link.dashboard)}`;
  1001→  }
  1002→
  1003→  if (!url && link.dashUri) {
  1004→    url = `dashboard/${link.dashUri}`;
  1005→  }
  1006→
  1007→  // some models are incomplete and have no dashboard or dashUri
  1008→  if (!url) {
  1009→    url = '/';
  1010→  }
  1011→
  1012→  if (link.keepTime) {
  1013→    url = urlUtil.appendQueryToUrl(url, `$${DataLinkBuiltInVars.keepTime}`);
  1014→  }
  1015→
  1016→  if (link.includeVars) {
  1017→    url = urlUtil.appendQueryToUrl(url, `$${DataLinkBuiltInVars.includeVars}`);
  1018→  }
  1019→
  1020→  if (link.params) {
  1021→    url = urlUtil.appendQueryToUrl(url, link.params);
  1022→  }
  1023→
  1024→  return {
  1025→    url: url,
  1026→    title: link.title,
  1027→    targetBlank: link.targetBlank,
  1028→  };
  1029→}
  1030→
  1031→function updateVariablesSyntax(text: string) {
  1032→  const legacyVariableNamesRegex = /(__series_name)|(\$__series_name)|(__value_time)|(__field_name)|(\$__field_name)/g;
  1033→
  1034→  return text.replace(legacyVariableNamesRegex, (match, seriesName, seriesName1, valueTime, fieldName, fieldName1) => {
  1035→    if (seriesName) {
  1036→      return '__series.name';
  1037→    }
  1038→    if (seriesName1) {
  1039→      return '${__series.name}';
  1040→    }
  1041→    if (valueTime) {
  1042→      return '__value.time';
  1043→    }
  1044→    if (fieldName) {
  1045→      return '__field.name';
  1046→    }
  1047→    if (fieldName1) {
  1048→      return '${__field.name}';
  1049→    }
  1050→    return match;
  1051→  });
  1052→}
  1053→
  1054→interface MigrateDatasourceNameOptions {
  1055→  returnDefaultAsNull: boolean;
  1056→}
  1057→
  1058→export function migrateDatasourceNameToRef(
  1059→  nameOrRef: string | DataSourceRef | null | undefined,
  1060→  options: MigrateDatasourceNameOptions
  1061→): DataSourceRef | null {
  1062→  if (options.returnDefaultAsNull && (nameOrRef == null || nameOrRef === 'default')) {
  1063→    return null;
  1064→  }
  1065→
  1066→  if (isDataSourceRef(nameOrRef)) {
  1067→    return nameOrRef;
  1068→  }
  1069→
  1070→  const ds = getDataSourceSrv().getInstanceSettings(nameOrRef);
  1071→  if (!ds) {
  1072→    return { uid: nameOrRef ? nameOrRef : undefined }; // not found
  1073→  }
  1074→
  1075→  return getDataSourceRef(ds);
